SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fin_m_bank_statement ON sc_fin_m_bank_statement CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_m_bank_statement() RETURNS trigger AS $BODY$
BEGIN
  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_fin_m_bank_statement
    where (bank_fin = NEW.bank_fin);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end  if;

  if coalesce(NEW.item_amount::text, '') = '' then NEW.item_amount := 0;end if;
  if coalesce(NEW.item_tax::text, '') = '' then NEW.item_tax :=0;end if;
  if coalesce(NEW.item_balance::text, '') = '' then NEW.item_balance :=0;end if;
  if coalesce(NEW.file_no::text, '') = '' then NEW.file_no := 0;end if;
  if coalesce(NEW.line_seqno::text, '') = '' then NEW.line_seqno := 0;end if;
  if coalesce(NEW.item_payable::text, '') = '' then NEW.item_payable := 0;end if;
  if (trim(both NEW.membership_no) IS NOT NULL AND (trim(both NEW.membership_no))::text <> '') then
    if is_number(NEW.membership_no) = '0' then
      CALL spa_dberror('T21:รายการบัญชีธนาคาร ทะเบียนสมาชิกต้องเป็นตัวเลขเท่านั้น !!!');
    end if;
  end if;
  if NEW.item_payable < 0 then
    CALL spa_dberror('T35:รายการบัญชีธนาคาร เงินคงเหลือทำรายการต้องเป็นค่าสัมบูรณ์(มากกว่าศูนย์เสมอ)');
  end if;

  if coalesce(trim(both NEW.cancel_status)::text, '') = '' then NEW.cancel_status := '0';end if;

  if NEW.cancel_status  = '0' then
    if coalesce(NEW.entry_date::text, '') = '' then NEW.entry_date := statement_timestamp();end if;
    if coalesce(trim(both NEW.entry_id )::text, '') = '' then NEW.entry_id := pka_com_function.fp_login_id;end if;
    if coalesce(trim(both NEW.entry_br )::text, '') = '' then NEW.entry_br := pka_com_function.fp_login_br;end if;
    if coalesce(trim(both NEW.entry_pc)::text, '') = '' then NEW.entry_pc := pka_com_function.fp_login_pc;end if;
  end if;

  if OLD.cancel_status = '0' and NEW.cancel_status = '1' then
    if (pka.auto_entry) then
      NEW.cancel_date := statement_timestamp();
      NEW.cancel_id := pka_com_function.fp_login_id;
      NEW.cancel_br := pka_com_function.fp_login_br;
      NEW.cancel_pc := pka_com_function.fp_login_pc;
    end if;
  end  if;

  if coalesce(trim(both NEW.link_recvpay)::text, '') = '' then NEW.link_recvpay :='0';end if;
  if coalesce(NEW.verify_seq::text, '') = '' then NEW.verify_seq := 0;end if;
  if coalesce(NEW.bank_error::text, '') = '' then NEW.bank_error := 0;end if;
  if coalesce(NEW.verify_amount::text, '') = '' then NEW.verify_amount := 0;end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fin_m_bank_statement() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fin_m_bank_statement
	BEFORE INSERT OR UPDATE ON sc_fin_m_bank_statement FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fin_m_bank_statement();

